logger = logging.getLogger(__name__)

class SecureMongoDBFilter:
    def __init__(self, connection_string: str, database_name: str):
        self.client = MongoClient(connection_string)
        self.db = self.client[database_name]
        self.allowed_functions = {
            'parseInt', 'parseFloat', 'isNaN', 'isFinite',
            'Math', 'Date', 'RegExp', 'String', 'Number'
        }
        self.allowed_properties = {
            'name', 'age', 'email', 'status', 'created_at',
            'updated_at', 'value', 'count', 'active'
        }
        
    def _sanitize_js_expression(self, expression: str) -> str:
        """Sanitize JavaScript expression to prevent injection"""
        if not isinstance(expression, str):
            raise ValueError("Expression must be a string")
            
        # Remove dangerous patterns
        dangerous_patterns = [
            r'function\s*\(',
            r'eval\s*\(',
            r'new\s+Function\s*\(',
            r'constructor\s*\(',
            r'__proto__',
            r'prototype',
            r'process',
            r'global',
            r'window',
            r'document',
            r'require\s*\(',
            r'import\s*\(',
            r'console',
            r'alert',
            r'prompt',
            r'confirm'
        ]
        
        for pattern in dangerous_patterns:
            if re.search(pattern, expression, re.IGNORECASE):
                raise ValueError("Potentially dangerous JavaScript expression detected")
                
        # Validate allowed properties and functions
        allowed_pattern = r'([a-zA-Z_$][a-zA-Z0-9_$]*\.)*[a-zA-Z_$][a-zA-Z0-9_$]*'
        matches = re.findall(allowed_pattern, expression)
        
        for match in matches:
            if '.' in match:
                parts = match.split('.')
                if parts[0] not in self.allowed_properties and parts[0] not in self.allowed_functions:
                    raise ValueError(f"Unauthorized property or function: {parts[0]}")
            else:
                if match not in self.allowed_properties and match not in self.allowed_functions:
                    raise ValueError(f"Unauthorized property or function: {match}")
                    
        return expression
        
    def _validate_collection(self, collection_name: str) -> bool:
        """Validate collection name"""
        if not isinstance(collection_name, str):
            return False
        if not re.match(r'^[a-zA-Z][a-zA-Z0-9_]*$', collection_name):
            return False
        return True
        
    def execute_filter(self, 
                      collection_name: str, 
                      filter_expression: str,
                      limit: Optional[int] = None,
                      skip: Optional[int] = None) -> Dict[str, Any]:
        """
        Execute secure MongoDB filter with JavaScript expression
        """
        try:
            # Validate inputs
            if not self._validate_collection(collection_name):
                raise ValueError("Invalid collection name")
                
            # Sanitize JavaScript expression
            sanitized_expression = self._sanitize_js_expression(filter_expression)
            
            # Get collection
            collection = self.db[collection_name]
            
            # Build query with $where
            query = {"$where": sanitized_expression}
            
            # Apply limit and skip if provided
            cursor = collection.find(query)
            
            if skip is not None:
                cursor = cursor.skip(skip)
                
            if limit is not None:
                cursor = cursor.limit(limit)
                
            # Execute query
            results = list(cursor)
            
            # Convert ObjectId to string for JSON serialization
            for doc in results:
                if '_id' in doc and isinstance(doc['_id'], ObjectId):
                    doc['_id'] = str(doc['_id'])
                    
            logger.info(f"Executed filter on {collection_name}: {len(results)} documents returned")
            
            return {
                "success": True,
                "count": len(results),
                "data": results,
                "query": filter_expression
            }
            
        except Exception as e:
            logger.error(f"Filter execution failed: {str(e)}")
            return {
                "success": False,
                "error": str(e),
                "data": []
            }
            
    def execute_aggregation_filter(self, 
                                 collection_name: str,
                                 pipeline: list,
                                 limit: Optional[int] = None) -> Dict[str, Any]:
        """
        Execute aggregation pipeline with secure filtering
        """
        try:
            if not self._validate_collection(collection_name):
                raise ValueError("Invalid collection name")
                
            collection = self.db[collection_name]
            
            # Apply limit if provided
            if limit:
                pipeline.append({"$limit": limit})
                
            # Execute aggregation
            results = list(collection.aggregate(pipeline))
            
            # Convert ObjectId to string for JSON serialization
            for doc in results:
                if '_id' in doc and isinstance(doc['_id'], ObjectId):
                    doc['_id'] = str(doc['_id'])
                    
            logger.info(f"Executed aggregation on {collection_name}: {len(results)} documents returned")
            
            return {
                "success": True,
                "count": len(results),
                "data": results
            }
            
        except Exception as e:
            logger.error(f"Aggregation execution failed: {str(e)}")
            return {
                "success": False,
                "error": str(e),
                "data": []
            }
            
    def close_connection(self):
        """Close MongoDB connection"""
        self.client.close()

